const { createRestrictedSyntaxConfigs } = require('./restricted-syntax.js');

const typeScriptFiles = [
	'**/*.ts',
	'**/*.tsx',
	'**/*.mts',
	'**/*.cts',
	'**/*.d.ts',
	'**/*.d.mts',
	'**/*.d.cts',
];

const testFiles = [
	'**/*.test.ts',
	'**/*.test.tsx',
	'**/*.spec.ts',
	'**/*.spec.tsx',
];

const generatedAttributionPattern =
	'(AI-assisted|AI generated|generated by AI|Generated by|Co-authored-by|AI-Assisted-by)';

function createRestrictedSyntaxGroups() {
	return [
		{
			files: typeScriptFiles,
			selectors: [
				{
					selector: 'TSAnyKeyword',
					message:
						'Do not introduce `any`. Use unknown, a domain type, or a generic constraint.',
				},
				{
					selector: 'TSAsExpression > TSAnyKeyword',
					message:
						'Do not silence type errors with `as any`. Fix the type boundary.',
				},
				{
					selector: 'TSAsExpression > TSAsExpression',
					message:
						'Do not use double assertions such as `as unknown as`. Add a type guard or proper adapter.',
				},
				{
					selector: `Literal[value=/${generatedAttributionPattern}/i]`,
					message:
						'Do not add generated or AI attribution strings to source output.',
				},
				{
					selector: `TemplateElement[value.raw=/${generatedAttributionPattern}/i]`,
					message:
						'Do not add generated or AI attribution strings to source output.',
				},
			],
		},
		{
			files: testFiles,
			selectors: [
				{
					selector:
						'CallExpression[callee.property.name="only"], CallExpression[callee.name=/^(it|test|describe)\\.only$/]',
					message: 'Do not commit focused tests.',
				},
				{
					selector:
						'CallExpression[callee.property.name="skip"], CallExpression[callee.name=/^(it|test|describe)\\.skip$/]',
					message: 'Do not commit skipped tests.',
				},
				{
					selector:
						'CallExpression[callee.property.name="toMatchSnapshot"], CallExpression[callee.name="toMatchSnapshot"]',
					message:
						'Do not use broad snapshot assertions for agent changes. Add focused assertions.',
				},
			],
		},
	];
}

const restrictedSyntaxGroups = createRestrictedSyntaxGroups();

const base = [
	{
		files: typeScriptFiles,
		rules: {
			'@typescript-eslint/ban-ts-comment': [
				'error',
				{
					'ts-expect-error': 'allow-with-description',
					'ts-ignore': true,
					'ts-nocheck': true,
					'ts-check': false,
					minimumDescriptionLength: 10,
				},
			],
			'@typescript-eslint/no-floating-promises': 'error',
			'@typescript-eslint/no-misused-promises': 'error',
			'@typescript-eslint/no-non-null-assertion': 'error',
			'no-empty': ['error', { allowEmptyCatch: false }],
		},
	},
	{
		rules: {
			'no-warning-comments': [
				'warn',
				{
					terms: ['todo', 'fixme', 'hack'],
					location: 'start',
				},
			],
		},
	},
];

function createAgentGuardrailsConfig() {
	return [...base, ...createRestrictedSyntaxConfigs(restrictedSyntaxGroups)];
}

const config = createAgentGuardrailsConfig();

module.exports = config;
module.exports.base = base;
module.exports.createAgentGuardrailsConfig = createAgentGuardrailsConfig;
module.exports.createRestrictedSyntaxGroups = createRestrictedSyntaxGroups;
module.exports.restrictedSyntaxGroups = restrictedSyntaxGroups;
